using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>() — strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>() — check-without-throwing ---

// 2a. Type the resolver CAN handle (default reflection resolver handles Person)
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGet Person   → found ({found!.Type.Name})");
else
    Console.WriteLine("TryGet Person   → not found");

// 2b. Type the resolver CANNOT handle (custom resolver that knows nothing)
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers = { (ti) => { if (ti.Type == typeof(Secret)) throw new NotSupportedException(); } }
    }
};

if (limited.TryGetTypeInfo<Secret>(out JsonTypeInfo<Secret>? secret))
    Console.WriteLine($"TryGet Secret   → found ({secret!.Type.Name})");
else
    Console.WriteLine("TryGet Secret   → not available (no exception thrown!)");

// --- records used above ---
public record Person(string Name, int Age);
public record Secret(string Key, string Value);

